const express = require('express');
const taskService = require('../services/task.service');
const authMiddleware = require('../middlewares/auth');

const router = express.Router();

router.post('/tasks', authMiddleware, async (req, res) => {
  try {
    const task = req.body;
    await taskService.createTask(task);
    res.status(201).json({ message: 'Task created' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

router.get('/tasks/:id/execute', authMiddleware, async (req, res) => {
  try {
    const taskId = req.params.id;
    await taskService.executeTask(taskId);
    res.json({ message: 'Task execution started' });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

router.get('/tasks/:id/logs', authMiddleware, async (req, res) => {
  try {
    const taskId = req.params.id;
    const logs = await taskService.getTaskLogs(taskId);
    res.json(logs);
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
});

