```go
package controllers

import (
	"net/http"
	"github.com/gin-gonic/gin"
	"task-execution-platform/backend/src/task-service/services"
)

func CreateTask(c *gin.Context) {
	var task services.TaskRequest
	if err := c.ShouldBindJSON(&task); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}
	err := services.CreateTask(task)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusCreated, gin.H{"message": "Task created"})
}

func ExecuteTask(c *gin.Context) {
	taskID := c.Param("id")
	err := services.ExecuteTask(taskID)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, gin.H{"message": "Task execution started"})
}

func GetTaskLogs(c *gin.Context) {
	taskID := c.Param("id")
	logs, err := services.GetTaskLogs(taskID)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, logs)
}
```

