package services

import (
	"database/sql"
	"log"
	"github.com/jmoiron/sqlx"
	"task-execution-platform/backend/src/task-service/models"
)

var db *sqlx.DB

func InitDB() {
	var err error
	db, err = sqlx.Connect("postgres", "user=postgres password=password dbname=task_execution_platform sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
}

func CreateTask(task models.TaskRequest) error {
	query := `INSERT INTO tasks (command, user_id) VALUES (:command, :user_id)`
	_, err := db.NamedExec(query, task)
	return err
}

func ExecuteTask(taskID string) error {
	query := `SELECT command FROM tasks WHERE id = $1`
	var command string
	err := db.Get(&command, query, taskID)
	if err != nil {
		return err
	}
	// Execute the command in a sandboxed environment
	// This is a placeholder for actual execution logic
	log.Printf("Executing task: %s", command)
	return nil
}

func GetTaskLogs(taskID string) (string, error) {
	query := `SELECT logs FROM tasks WHERE id = $1`
	var logs string
	err := db.Get(&logs, query, taskID)
	if err != nil {
		return "", err
	}
	return logs, nil
}
